// =========================
// CONFIG - productos a excluir por ID
// =========================
const PRODUCTOS_EXCLUIDOS = new Set([]);

// =========================
// INPUT
// =========================
const rows = $input.first().json.result ?? [];

// =========================
// Helpers
// =========================
const normalize = (s) =>
  String(s ?? "").replace(/\s+/g, " ").trim().toLowerCase();

const tieneValor = (v) =>
  v !== null && v !== undefined && String(v).trim() !== "";

const empresasPermitidas = [
  "southgenetics llc argentina",
  "southgenetics llc méxico",
  "southgenetics llc uruguay",
  "southgenetics llc colombia",
  "southgenetics llc chile",
  "southgenetics llc venezuela",
  "southgenetics llc"
];

const esEmpresaValida = (empresa) =>
  empresasPermitidas.includes(normalize(empresa));

// =========================
// Validación
// =========================
if (rows.length > 0) {
  if (!Object.prototype.hasOwnProperty.call(rows[0], "company_id"))
    throw new Error("La respuesta no trae company_id. Revisá el read_group.");

  if (!Object.prototype.hasOwnProperty.call(rows[0], "partner_id"))
    throw new Error("La respuesta no trae partner_id. Revisá el read_group.");

  if (!Object.prototype.hasOwnProperty.call(rows[0], "referrer_id"))
    throw new Error("La respuesta no trae referrer_id. Revisá el read_group.");

  if (!Object.prototype.hasOwnProperty.call(rows[0], "product_id"))
    throw new Error("La respuesta no trae product_id. Revisá el read_group.");

  if (!Object.prototype.hasOwnProperty.call(rows[0], "product_categ_id"))
    throw new Error("La respuesta no trae product_categ_id. Revisá el read_group.");

  if (!Object.prototype.hasOwnProperty.call(rows[0], "move_id"))
    throw new Error("La respuesta no trae move_id. Revisá el read_group.");
}

// =========================
// Limpieza, filtrado y salida
// =========================
const resultado = [];

for (const r of rows) {
  const empresa = Array.isArray(r.company_id)
    ? String(r.company_id[1] ?? "").trim()
    : "";

  const empresa_id = Array.isArray(r.company_id)
    ? r.company_id[0]
    : null;

  const producto = Array.isArray(r.product_id)
    ? String(r.product_id[1] ?? "").trim()
    : "";

  const producto_id = Array.isArray(r.product_id)
    ? r.product_id[0]
    : null;

  const product_categ = Array.isArray(r.product_categ_id)
    ? String(r.product_categ_id[1] ?? "").trim()
    : "";

  const product_categ_id = Array.isArray(r.product_categ_id)
    ? r.product_categ_id[0]
    : null;

  const partner = Array.isArray(r.partner_id)
    ? String(r.partner_id[1] ?? "").trim()
    : "";

  const partner_id = Array.isArray(r.partner_id)
    ? r.partner_id[0]
    : null;

  const referrer = Array.isArray(r.referrer_id)
    ? String(r.referrer_id[1] ?? "").trim()
    : "";

  const referrer_id = Array.isArray(r.referrer_id)
    ? r.referrer_id[0]
    : null;

  const move_id = Array.isArray(r.move_id)
    ? r.move_id[0]
    : null;

  const move_nombre = Array.isArray(r.move_id)
    ? String(r.move_id[1] ?? "").trim()
    : "";

  const fecha_dia = String(r["invoice_date:day"] ?? "").trim();

  const fecha_dia_inicio =
    String(r.__range?.["invoice_date:day"]?.from ?? "").trim();

  const cantidad = Number(r.quantity ?? 0);

  const precio_total = Number(r.price_subtotal ?? 0);

  // =========================
  // Filtros
  // =========================
  const fechaValida =
    tieneValor(fecha_dia_inicio) || tieneValor(fecha_dia);

  if (
    !fechaValida ||
    !tieneValor(empresa) ||
    !tieneValor(partner) ||
    !tieneValor(producto) ||
    !esEmpresaValida(empresa) ||
    PRODUCTOS_EXCLUIDOS.has(producto_id)
  ) continue;

  resultado.push({
    fecha_dia,
    fecha_dia_inicio,

    move_id,
    move_nombre,

    empresa_id,
    empresa,

    partner_id,
    partner,

    referrer_id,
    referrer,

    product_categ_id,
    product_categ,

    producto_id,
    producto,

    cantidad,

    precio_unitario:
      cantidad !== 0
        ? precio_total / cantidad
        : 0,

    precio_total,
  });
}

// =========================
// Ordenar
// =========================
resultado.sort((a, b) => {
  if ((a.fecha_dia_inicio || "") < (b.fecha_dia_inicio || "")) return -1;
  if ((a.fecha_dia_inicio || "") > (b.fecha_dia_inicio || "")) return 1;

  if ((a.empresa || "") < (b.empresa || "")) return -1;
  if ((a.empresa || "") > (b.empresa || "")) return 1;

  if ((a.partner || "") < (b.partner || "")) return -1;
  if ((a.partner || "") > (b.partner || "")) return 1;

  if ((a.producto || "") < (b.producto || "")) return -1;
  if ((a.producto || "") > (b.producto || "")) return 1;

  return 0;
});

// =========================
